  ('optician-moex-01818', 'optician', 'optician-moex-108-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '對於垂直稜鏡的敘述，單眼前方放置一基底朝上的稜鏡所產生效果，等同於另一眼放置何種稜鏡方向可 產生同等效應？', '["基底朝上", "基底朝內", "基底朝下", "基底朝外"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "8df8b65115b1", "answer_pdf_sha1": "d875f69b2637", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
